if (!msg.payload || !msg.payload.features) { node.warn('States GeoJSON failed'); return null; }
flow.set('statesGeoJSON', msg.payload);
node.log('Cached ' + msg.payload.features.length + ' state features');
msg.payload = { command: { map: {
    overlay: 'US States',
    geojson: flow.get('statesGeoJSON'),
    opt: { style: "function() { return { color: '#444', weight: 1.5, fill: false } }" },
    visible: false, fit: false, clickable: false
}}};
return msg;

if (!msg.payload || !msg.payload.features) { node.warn('Counties GeoJSON failed'); return null; }
flow.set('countiesGeoJSON', msg.payload);
node.log('Cached ' + msg.payload.features.length + ' county features');
msg.payload = { command: { map: {
    overlay: 'US Counties',
    geojson: flow.get('countiesGeoJSON'),
    opt: { style: "function() { return { color: '#888', weight: 0.7, fill: false } }" },
    visible: false, fit: false, clickable: false
}}};
return msg;

var data = msg.payload;
if (!data || !data.features) { node.warn('NOAA API failed: ' + JSON.stringify(msg.statusCode)); return null; }

var now = Date.now();
var sevStyle = {
    'Extreme':  { stroke: '#CC0000', fillColor: '#FF0000', fillOpacity: 0.40 },
    'Severe':   { stroke: '#CC4400', fillColor: '#FF6600', fillOpacity: 0.30 },
    'Moderate': { stroke: '#AAAA00', fillColor: '#FFEE00', fillOpacity: 0.22 },
    'Minor':    { stroke: '#0055AA', fillColor: '#3399FF', fillOpacity: 0.15 },
    'Unknown':  { stroke: '#555555', fillColor: '#999999', fillOpacity: 0.10 }
};

var features = [];
data.features.forEach(function(f) {
    if (!f.geometry) return;
    if (f.properties.expires && new Date(f.properties.expires).getTime() < now) return;
    var sev = f.properties.severity || 'Unknown';
    var sp  = sevStyle[sev] || sevStyle['Unknown'];
    var feat = JSON.parse(JSON.stringify(f));
    feat.properties.style = { color: sp.stroke, fillColor: sp.fillColor, fillOpacity: sp.fillOpacity, weight: 2 };
    feat.properties.name = feat.properties.event || 'Alert';
    features.push(feat);
});

node.log('NOAA: ' + features.length + ' active alerts');
var fc = { type: 'FeatureCollection', features: features };
flow.set('noaaGeoJSON', fc);

msg.payload = { command: { map: {
    overlay: 'NOAA Alerts',
    geojson: fc,

    visible: true, fit: false
}}};
return msg;

// ── Owned Meshtastic nodes whitelist ──────────────────────────────────────
// Add your nodes as '!hexid': 'display name'
// Node hex ID shown in Meshtastic app: Radio Config → User → Node ID
var ownedNodes = {
    '!55c6ddbc': 'T-Beam',
};
flow.set('meshOwnedNodes', ownedNodes);
node.log('Mesh whitelist loaded: ' + Object.keys(ownedNodes).length + ' owned nodes');
return null;

if (msg.topic.indexOf('/json/') === -1) return null;

var payload = msg.payload;
if (!payload || !payload.from) return null;

var nodeId   = '!' + payload.from.toString(16).padStart(8, '0');
var msgType  = payload.type;
var registry = flow.get('meshRegistry') || {};
registry[nodeId] = registry[nodeId] || { id: nodeId };

if (msgType === 'nodeinfo' && payload.payload) {
    var info = payload.payload;
    registry[nodeId].name = info.longname || info.shortname || nodeId;
    flow.set('meshRegistry', registry);
    return null;
}

if (msgType === 'position' && payload.payload) {
    var pos = payload.payload;
    var lat = (pos.latitude_i  || 0) / 1e7;
    var lon = (pos.longitude_i || 0) / 1e7;
    if (lat === 0 && lon === 0) return null;

    registry[nodeId].lat = lat;
    registry[nodeId].lon = lon;
    flow.set('meshRegistry', registry);

    var ownedNodes = flow.get('meshOwnedNodes') || {};
    var isOwned    = ownedNodes.hasOwnProperty(nodeId);
    var name       = ownedNodes[nodeId] || registry[nodeId].name || nodeId;

    var meshMarker = {
        name:      name,
        lat:       lat,
        lon:       lon,
        layer:     'Meshtastic',
        icon:      'fa-dot-circle-o',
        iconColor: isOwned ? 'blue' : 'green',
        tooltip:   name + ' (' + nodeId + ')',
        ttl:       600
    };
    var meshCache = flow.get('meshMarkers') || {};
    meshCache[name] = meshMarker;
    flow.set('meshMarkers', meshCache);

    // Re-emit any topology lines involving this node now that we have its position
    var topoLines = rebuildTopologyLines(nodeId, flow, registry);
    var out = [{ payload: meshMarker }];
    for (var i = 0; i < topoLines.length; i++) out.push({ payload: topoLines[i] });
    return out;
}

if (msgType === 'neighborinfo' && payload.payload) {
    var ni = payload.payload;
    var neighbors = ni.neighbors || [];
    var topology = flow.get('meshTopology') || {};
    topology[nodeId] = { ts: Date.now(), neighbors: {} };
    for (var j = 0; j < neighbors.length; j++) {
        var nb = neighbors[j];
        var nbId = '!' + nb.node_id.toString(16).padStart(8, '0');
        topology[nodeId].neighbors[nbId] = nb.snr || 0;
    }
    flow.set('meshTopology', topology);

    var lines = rebuildTopologyLines(nodeId, flow, registry);
    if (lines.length === 0) return null;
    return lines.map(function(l) { return { payload: l }; });
}

return null;

// ── helpers ───────────────────────────────────────────────────────────────

function snrToLinkStyle(snr) {
    if (snr >= 5)  return { color: '#00DD00', weight: 3 };
    if (snr >= 0)  return { color: '#AADD00', weight: 2 };
    if (snr >= -7) return { color: '#FFAA00', weight: 2 };
    return { color: '#FF4444', weight: 1 };
}

function rebuildTopologyLines(changedNodeId, flow, registry) {
    var topology = flow.get('meshTopology') || {};
    var lines = [];
    var seen = {};
    var allSources = Object.keys(topology);
    for (var s = 0; s < allSources.length; s++) {
        var fromId = allSources[s];
        var entry = topology[fromId];
        if (!entry || !entry.neighbors) continue;
        var nbKeys = Object.keys(entry.neighbors);
        for (var n = 0; n < nbKeys.length; n++) {
            var toId = nbKeys[n];
            if (fromId !== changedNodeId && toId !== changedNodeId) continue;
            var edgePair = [fromId, toId].sort();
            var edgeName = 'link-' + edgePair[0].replace('!','') + '-' + edgePair[1].replace('!','');
            if (seen[edgeName]) continue;
            seen[edgeName] = true;

            var fromNode = registry[fromId];
            var toNode   = registry[toId];
            if (!fromNode || !fromNode.lat || !toNode || !toNode.lat) continue;

            var snr = entry.neighbors[toId];
            // Use best SNR from either direction
            if (topology[toId] && topology[toId].neighbors && topology[toId].neighbors[fromId] !== undefined) {
                snr = Math.max(snr, topology[toId].neighbors[fromId]);
            }
            var style = snrToLinkStyle(snr);
            lines.push({
                name:    edgeName,
                line:    [
                    { lat: fromNode.lat, lng: fromNode.lon },
                    { lat: toNode.lat,   lng: toNode.lon   }
                ],
                color:   style.color,
                weight:  style.weight,
                opacity: 0.75,
                layer:   'Mesh Links',
                ttl:     1800,
                tooltip: snr.toFixed(1) + ' dB'
            });
        }
    }
    return lines;
}

if (!msg.payload || msg.payload.action !== 'connected') return null;
var sid = msg._sessionid;
var msgs = [];

// Branding
msgs.push({ payload: { command: { toptitle: 'CrypTAK WebMap' } }, _sessionid: sid });
msgs.push({ payload: { command: { toplogo: '/cryptak-logo.png' } }, _sessionid: sid });
msgs.push({ payload: { command: { coords: 'mgrs' } }, _sessionid: sid });
var legend = flow.get('legendHtml');
if (legend) msgs.push({ payload: { command: { legend: legend } }, _sessionid: sid });

// GeoJSON overlays
var stGeo = flow.get('statesGeoJSON');
if (stGeo) msgs.push({ payload: { command: { map: { overlay: 'US States', geojson: stGeo, opt: { style: "function() { return { color: '#444', weight: 1.5, fill: false } }" }, visible: false, fit: false, clickable: false } } }, _sessionid: sid });
var coGeo = flow.get('countiesGeoJSON');
if (coGeo) msgs.push({ payload: { command: { map: { overlay: 'US Counties', geojson: coGeo, opt: { style: "function() { return { color: '#888', weight: 0.7, fill: false } }" }, visible: false, fit: false, clickable: false } } }, _sessionid: sid });
var noaaGeo = flow.get('noaaGeoJSON');
if (noaaGeo && noaaGeo.features && noaaGeo.features.length > 0) msgs.push({ payload: { command: { map: { overlay: 'NOAA Alerts', geojson: noaaGeo,  visible: true, fit: false } } }, _sessionid: sid });

// TAK markers
var takCache = flow.get('takMarkers') || {};
var tKeys = Object.keys(takCache);
for (var i = 0; i < tKeys.length; i++) {
    var m = Object.assign({}, takCache[tKeys[i]]);
    msgs.push({ payload: m, _sessionid: sid });
}

// Mesh markers
var meshCache = flow.get('meshMarkers') || {};
var mKeys = Object.keys(meshCache);
for (var j = 0; j < mKeys.length; j++) {
    msgs.push({ payload: meshCache[mKeys[j]], _sessionid: sid });
}

// Replay tracker trails
var history = flow.get('trackerHistory') || {};
var trailDuration = flow.get('trailDuration');
if (trailDuration === undefined || trailDuration === null) trailDuration = 3600000;
if (trailDuration > 0) {
    var displayCutoff = Date.now() - trailDuration;
    var tKeys2 = Object.keys(history);
    for (var k = 0; k < tKeys2.length; k++) {
        var tkName = tKeys2[k];
        var tkMarker = takCache[tkName];
        if (!tkMarker) continue;
        var tTrail = history[tkName].filter(function(p) { return p.ts >= displayCutoff; });
        if (tTrail.length >= 2) {
            msgs.push({ payload: {
                name: 'trail-' + tkName,
                line: tTrail.map(function(p) { return { lat: p.lat, lng: p.lon }; }),
                color: tkMarker.iconColor,
                weight: 3, opacity: 0.6,
                layer: 'TAK Tracks', ttl: 600
            }, _sessionid: sid });
        }
    }
}


// Mesh topology lines
var meshTopology = flow.get('meshTopology') || {};
var meshReg = flow.get('meshRegistry') || {};
var topoSeen = {};
var topoSources = Object.keys(meshTopology);
for (var tl = 0; tl < topoSources.length; tl++) {
    var tlFrom = topoSources[tl];
    var tlEntry = meshTopology[tlFrom];
    if (!tlEntry || !tlEntry.neighbors) continue;
    var tlNbs = Object.keys(tlEntry.neighbors);
    for (var tn = 0; tn < tlNbs.length; tn++) {
        var tlTo = tlNbs[tn];
        var epair = [tlFrom, tlTo].sort();
        var ename = 'link-' + epair[0].replace('!','') + '-' + epair[1].replace('!','');
        if (topoSeen[ename]) continue;
        topoSeen[ename] = true;
        var fnNode = meshReg[tlFrom];
        var tnNode = meshReg[tlTo];
        if (!fnNode || !fnNode.lat || !tnNode || !tnNode.lat) continue;
        var lsnr = tlEntry.neighbors[tlTo];
        if (meshTopology[tlTo] && meshTopology[tlTo].neighbors && meshTopology[tlTo].neighbors[tlFrom] !== undefined) {
            lsnr = Math.max(lsnr, meshTopology[tlTo].neighbors[tlFrom]);
        }
        var lcolor, lweight;
        if (lsnr >= 5)       { lcolor = '#00DD00'; lweight = 3; }
        else if (lsnr >= 0)  { lcolor = '#AADD00'; lweight = 2; }
        else if (lsnr >= -7) { lcolor = '#FFAA00'; lweight = 2; }
        else                 { lcolor = '#FF4444'; lweight = 1; }
        msgs.push({ payload: {
            name: ename,
            line: [{ lat: fnNode.lat, lng: fnNode.lon }, { lat: tnNode.lat, lng: tnNode.lon }],
            color: lcolor, weight: lweight, opacity: 0.75,
            layer: 'Mesh Links', ttl: 1800,
            tooltip: lsnr.toFixed(1) + ' dB'
        }, _sessionid: sid });
    }
}

node.log('Replaying ' + msgs.length + ' items to session ' + sid);
return [msgs];

var legendHtml = '<div style="font-family:sans-serif;font-size:12px;line-height:1.6;">'
    + '<b style="font-size:14px;">CrypTAK</b><br>'
